meta.script:
(function(){
  const gameUrl = "https://cdn.jsdelivr.net/gh/un-zynq/singlefilegames/drift-hunters-pro.html";

  fetch(gameUrl)
    .then(response => response.text())
    .then(html => {
      // Voeg een base tag toe aan de HTML voordat we hem in een blob stoppen
      const modifiedHtml = html

      const blob = new Blob([modifiedHtml], { type: 'text/html' });
      const blobUrl = URL.createObjectURL(blob);

      const iframe = document.getElementById('gameFrame');
      iframe.src = blobUrl;

      // Revoke de blob URL na het laden om memory leaks te voorkomen
      iframe.onload = function() {
        URL.revokeObjectURL(blobUrl);
      };
    })
    .catch(error => {
      const iframe = document.getElementById('gameFrame');
      const iframeDoc = iframe.contentWindow.document;
      iframeDoc.open();
      iframeDoc.write('Failed to load game: ' + error.message + '');
      iframeDoc.close();
    });
})();
